mapper.select:
select e.id, e.w_en, e.w_zh, e.w_phonetic, e.w_audio, e.w_memo_skill, e.w_unit, e.w_mold
from e_words e
where e.id not in (select es.w_id from e_studied es where es.u_id = #{uId})
and e.w_mold = #{wMold}

    and e.w_unit = #{wUnit}

order by e.w_unit limit 1

select w.* from e_words w, e_sign s where w.id = s.w_id and s.u_id = #{uId}

    and s.l_is_memo=1

order by s.l_id DESC

select * from e_words as ew join e_sign as es
    on ew.id = es.w_id where es.u_id=#{uId}
    order by es.l_id
